import{_ as a,a as t,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"د Yandex Channel اضافه کول","description":"","frontmatter":{},"headers":[],"relativePath":"ps/upload/yandex.md","filePath":"ps/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"ps/upload/yandex.md"};function c(p,e,h,u,m,x){return i(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="د-yandex-channel-اضافه-کول" tabindex="-1">د Yandex Channel اضافه کول <a class="header-anchor" href="#د-yandex-channel-اضافه-کول" aria-label="Permalink to &quot;د Yandex Channel اضافه کول&quot;">​</a></h1><h2 id="مخکې-څه-ته-اړتیا-لرئ" tabindex="-1">مخکې څه ته اړتیا لرئ <a class="header-anchor" href="#مخکې-څه-ته-اړتیا-لرئ" aria-label="Permalink to &quot;مخکې څه ته اړتیا لرئ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>اړتیا</th><th>ولې ورته اړتیا ده</th></tr></thead><tbody><tr><td>Yandex account</td><td>sign in او Yandex Disk authorize کولو لپاره</td></tr><tr><td>Yandex OAuth app</td><td>د <code>Client ID</code> او <code>Client Secret</code> جوړولو لپاره</td></tr><tr><td>ستاسو ImgBed domain</td><td>د OAuth redirect URI لپاره</td></tr><tr><td>کافي Yandex Disk storage</td><td>د فایلونو اصلي storage ځای</td></tr></tbody></table><h2 id="د-تنظیم-پړاوونه" tabindex="-1">د تنظیم پړاوونه <a class="header-anchor" href="#د-تنظیم-پړاوونه" aria-label="Permalink to &quot;د تنظیم پړاوونه&quot;">​</a></h2><h3 id="_1-ګام-yandex-oauth-app-جوړ-کړئ" tabindex="-1">1 ګام: Yandex OAuth App جوړ کړئ <a class="header-anchor" href="#_1-ګام-yandex-oauth-app-جوړ-کړئ" aria-label="Permalink to &quot;1 ګام: Yandex OAuth App جوړ کړئ&quot;">​</a></h3><ol><li>د Yandex OAuth app جوړولو پاڼه پرانیزئ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>که sign in ته ولېږدول شوئ، لومړی خپل Yandex account ته sign in وکړئ.</li><li>نوی app جوړ کړئ.</li><li>app ته داسې نوم ورکړئ چې وپېژندل شي، لکه <code>imgbed-yandex</code>.</li><li>د callback یا redirect URL settings ومومئ.</li><li>دا ولیکئ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="_2-ګام-permissions-تایید-کړئ" tabindex="-1">2 ګام: Permissions تایید کړئ <a class="header-anchor" href="#_2-ګام-permissions-تایید-کړئ" aria-label="Permalink to &quot;2 ګام: Permissions تایید کړئ&quot;">​</a></h3><p>د اوسني ImgBed Yandex integration لپاره، د <code>Yandex.Disk REST API</code> لاندې دا څلور permissions وساتئ:</p><table tabindex="0"><thead><tr><th>Permission</th><th>موخه</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>ImgBed ته اجازه ورکوي چې فایلونه په app folder کې وساتي</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>فایلونه او download links لولي</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>فایلونه upload کوي، folders جوړوي او فایلونه ړنګوي</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>disk quota او used space لولي</td></tr></tbody></table><p>که د <code>Yandex ID API</code> لاندې دا permissions هم ښکاره شي، اختیاري دي:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>سپارښتنه</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>اختیاري</td></tr><tr><td><code>Access to email address</code></td><td>اختیاري</td></tr></tbody></table><p>د upload، download، deletion او quota اصلي ځانګړنې تر ډېره پر همدې پورته څلورو <code>Yandex.Disk REST API</code> permissions ولاړې دي.</p><p><img src="'+a+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="_3-ګام-app-credentials-copy-کړئ" tabindex="-1">3 ګام: App Credentials copy کړئ <a class="header-anchor" href="#_3-ګام-app-credentials-copy-کړئ" aria-label="Permalink to &quot;3 ګام: App Credentials copy کړئ&quot;">​</a></h3><p>کله چې app جوړ شو، دا copy کړئ:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+t+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="_4-ګام-د-yandex-channel-ډک-کړئ" tabindex="-1">4 ګام: د Yandex Channel ډک کړئ <a class="header-anchor" href="#_4-ګام-د-yandex-channel-ډک-کړئ" aria-label="Permalink to &quot;4 ګام: د Yandex Channel ډک کړئ&quot;">​</a></h3><p>په Upload Settings کې <code>Yandex</code> وټاکئ او دا fields ډک کړئ:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>څه ولیکئ</th></tr></thead><tbody><tr><td>Channel name</td><td>داسې نوم چې وپېژندل شي، لکه <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>د Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>د Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>اوس یې تش پرېږدئ</td></tr><tr><td>Root directory</td><td>اختیاري. Default یې <code>imgbed</code> دی.</td></tr></tbody></table><p><img src="'+d+'" alt="Edit channel config" loading="lazy"></p><h3 id="_5-ګام-refresh-token-واخلئ" tabindex="-1">5 ګام: Refresh Token واخلئ <a class="header-anchor" href="#_5-ګام-refresh-token-واخلئ" aria-label="Permalink to &quot;5 ګام: Refresh Token واخلئ&quot;">​</a></h3><ol><li>په ImgBed کې <code>Get Token</code> کلیک کړئ.</li><li>هغه Yandex account ته sign in وکړئ چې نښلول یې غواړئ.</li><li>د authorization غوښتنه approve کړئ.</li><li>callback page به <code>Refresh Token</code> ښکاره کړي.</li><li>هغه copy کړئ.</li><li>بېرته ImgBed ته راشئ او د <code>Refresh Token</code> field کې یې paste کړئ.</li></ol><p><img src="'+n+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="_6-ګام-channel-خوندي-کړئ" tabindex="-1">6 ګام: Channel خوندي کړئ <a class="header-anchor" href="#_6-ګام-channel-خوندي-کړئ" aria-label="Permalink to &quot;6 ګام: Channel خوندي کړئ&quot;">​</a></h3><p>کله چې ټول fields ډک شول، channel save کړئ.</p><h2 id="چټک-بهیر" tabindex="-1">چټک بهیر <a class="header-anchor" href="#چټک-بهیر" aria-label="Permalink to &quot;چټک بهیر&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Create an app</span></span>
<span class="line"><span>-&gt; Add https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Confirm Yandex Disk permissions</span></span>
<span class="line"><span>-&gt; Copy Client ID and Client Secret</span></span>
<span class="line"><span>-&gt; Fill Client ID / Client Secret into ImgBed</span></span>
<span class="line"><span>-&gt; Click Get Token</span></span>
<span class="line"><span>-&gt; Copy the Refresh Token from the callback page</span></span>
<span class="line"><span>-&gt; Paste it back into ImgBed and save</span></span></code></pre></div><h2 id="ماخذونه" tabindex="-1">ماخذونه <a class="header-anchor" href="#ماخذونه" aria-label="Permalink to &quot;ماخذونه&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const y=o(r,[["render",c]]);export{k as __pageData,y as default};
